#include<bits/stdc++.h>
using namespace std;
long long pre[100005],a[100005];
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		pre[i]=a[i]-a[i-1];
	}
	long long mini=0,maxi=0;
	for(int i=2;i<=n;i++){
		if(pre[i]>=0)maxi+=pre[i];
		else mini+=pre[i];
	}
//	cout<<endl;
	cout<<max(abs(maxi),abs(mini))<<endl;
	cout<<abs(maxi+mini)+1<<endl;
}
